/* ─────────────────────────────────────────
   MOVIE POSTER CARD
   Shows real TMDB poster image.
   Falls back to gradient if image not ready.
───────────────────────────────────────── */
function MoviePoster({ movie, h = 240 }) {
  const [err, setErr] = useState(false);

  return (
    <div
      style={{
        width: "100%",
        height: h,
        borderRadius: 6,
        overflow: "hidden",
        position: "relative",
        background: movie.gradient,
      }}
    >
      {/* Real poster image — shown as soon as thumb is available */}
      {movie.thumb && !err && (
        <img
          src={movie.thumb}
          alt={movie.title}
          onError={() => setErr(true)}
          style={{
            position: "absolute",
            inset: 0,
            width: "100%",
            height: "100%",
            objectFit: "cover",
            display: "block",
          }}
        />
      )}

      {/* Gradient fallback title (shown while loading or on error) */}
      {(!movie.thumb || err) && (
        <>
          <div style={{ position: "absolute", top: 8, left: 8, opacity: 0.8 }}>
            <svg viewBox="0 0 111 30" fill="none" width="28">
              <path d="M0 0v30c2-.002 4 .04 6 .12V0H0z" fill="#E50914" />
            </svg>
          </div>
          <div
            style={{
              position: "absolute",
              bottom: 8,
              left: 8,
              right: 8,
              background: "rgba(0,0,0,0.6)",
              borderRadius: 4,
              padding: "4px 8px",
              fontSize: 11,
              fontWeight: 800,
              color: "white",
              textAlign: "center",
              backdropFilter: "blur(4px)",
            }}
          >
            {movie.title}
          </div>
          {/* shimmer while loading */}
          {!movie.thumb && !err && (
            <div
              style={{
                position: "absolute",
                inset: 0,
                background:
                  "linear-gradient(90deg,transparent 25%,rgba(255,255,255,0.07) 50%,transparent 75%)",
                backgroundSize: "200% 100%",
                animation: "shimmer 1.4s infinite",
              }}
            />
          )}
        </>
      )}

      {/* Language badge */}
      {movie.language && (
        <div
          style={{
            position: "absolute",
            top: 6,
            right: 6,
            fontSize: 9,
            fontWeight: 800,
            background: "rgba(0,0,0,0.8)",
            padding: "2px 5px",
            borderRadius: 3,
            color: "#eee",
            letterSpacing: 0.5,
            zIndex: 2,
          }}
        >
          {movie.language.split("/")[0].toUpperCase()}
        </div>
      )}
    </div>
  );
}

/* ─────────────────────────────────────────
   HERO BACKGROUND
   Uses real TMDB backdrop (wide cinematic image).
   Falls back to heroGradient.
───────────────────────────────────────── */
function HeroBanner({ movie }) {
  const [bgErr, setBgErr] = useState(false);
  const hasBackdrop = movie.backdrop && !bgErr;

  return (
    <div
      style={{
        position: "absolute",
        inset: 0,
        background: movie.heroGradient || movie.gradient,
      }}
    >
      {hasBackdrop && (
        <img
          key={movie.backdrop} // re-mount on change
          src={movie.backdrop}
          alt=""
          onError={() => setBgErr(true)}
          style={{
            position: "absolute",
            inset: 0,
            width: "100%",
            height: "100%",
            objectFit: "cover",
            objectPosition: "center top",
            display: "block",
          }}
        />
      )}
      {/* Dark gradients over the backdrop so text is readable */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "linear-gradient(to right, rgba(0,0,0,0.85) 0%, rgba(0,0,0,0.5) 50%, rgba(0,0,0,0.1) 100%)",
        }}
      />
      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "linear-gradient(to top, #141414 0%, rgba(20,20,20,0.2) 30%, transparent 100%)",
        }}
      />
    </div>
  );
}

/* ─────────────────────────────────────────
   MOVIE CARD (smooth hover — reduced scale)
───────────────────────────────────────── */
function MovieCard({ movie, onSetHero, onPlay, onToggleList, inList }) {
  const [hovered, setHovered] = useState(false);
  const timerRef = useRef(null);

  // Debounce hover to avoid flickering during fast mouse movement
  const handleEnter = () => {
    clearTimeout(timerRef.current);
    timerRef.current = setTimeout(() => setHovered(true), 120);
  };
  const handleLeave = () => {
    clearTimeout(timerRef.current);
    setHovered(false);
  };

  const handleClick = () => {
    onSetHero(movie);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  return (
    <div
      onMouseEnter={handleEnter}
      onMouseLeave={handleLeave}
      style={{
        flexShrink: 0,
        width: 155,
        cursor: "pointer",
        /* Use transformOrigin center so scale doesn't shift neighbours.
           The row has overflowY:visible + fixed paddingBottom so the
           expanded card floats above without pushing siblings. */
        transform: hovered ? "scale(1.07)" : "scale(1)",
        transformOrigin: "center center",
        transition: "transform 0.25s ease",
        zIndex: hovered ? 30 : 1,
        position: "relative",
      }}
    >
      <div
        style={{
          borderRadius: 6,
          overflow: "hidden",
          boxShadow: hovered
            ? "0 10px 30px rgba(0,0,0,0.85)"
            : "0 2px 8px rgba(0,0,0,0.45)",
          transition: "box-shadow 0.25s ease",
        }}
      >
        <div onClick={handleClick}>
          <MoviePoster movie={movie} />
        </div>

        {/* Info panel — slides in smoothly */}
        <div
          style={{
            background: "#181818",
            maxHeight: hovered ? 84 : 0,
            opacity: hovered ? 1 : 0,
            overflow: "hidden",
            transition: "max-height 0.28s ease, opacity 0.22s ease",
            borderRadius: "0 0 6px 6px",
          }}
        >
          <div style={{ padding: "10px 11px" }}>
            <div style={{ display: "flex", gap: 5, marginBottom: 7 }}>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  onPlay(movie);
                }}
                style={iconBtn("white", "black")}
                title="Play"
              >
                <I.Play />
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  onToggleList(movie);
                }}
                style={iconBtn(
                  "transparent",
                  inList ? "#46d369" : "white",
                  inList ? "#46d369" : "#aaa",
                )}
                title="My List"
              >
                {inList ? <I.Check /> : <I.Plus />}
              </button>
              <button
                style={iconBtn("transparent", "white", "#aaa")}
                title="Rate"
              >
                <I.Thumb />
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  handleClick();
                }}
                style={{
                  ...iconBtn("transparent", "white", "#aaa"),
                  marginLeft: "auto",
                }}
                title="More Info"
              >
                <I.Info />
              </button>
            </div>
            <div style={{ display: "flex", gap: 5, alignItems: "center" }}>
              <span style={{ color: "#46d369", fontSize: 11, fontWeight: 700 }}>
                {movie.match}%
              </span>
              <span
                style={{
                  color: "#aaa",
                  fontSize: 10,
                  border: "1px solid #444",
                  padding: "1px 4px",
                  borderRadius: 2,
                }}
              >
                {movie.rating}
              </span>
              <span style={{ color: "#ccc", fontSize: 10, marginLeft: 2 }}>
                {movie.genre?.split("·")[0]?.trim()}
              </span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

const iconBtn = (bg, color, border) => ({
  background: bg === "white" ? "white" : "transparent",
  border: border ? `2px solid ${border}` : "none",
  borderRadius: "50%",
  width: 32,
  height: 32,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  cursor: "pointer",
  color,
  flexShrink: 0,
});

/* ─────────────────────────────────────────
   SCROLLABLE ROW
───────────────────────────────────────── */
const CARD_WIDTH = 155 + 8; // card width + gap

function Row({ label, movies, onSetHero, onPlay, myList, onToggleList }) {
  const ref = useRef(null);
  const [canLeft, setCanLeft] = useState(false);
  const [canRight, setCanRight] = useState(true);

  const updateArrows = () => {
    const el = ref.current;
    if (!el) return;
    setCanLeft(el.scrollLeft > 4);
    setCanRight(el.scrollLeft < el.scrollWidth - el.clientWidth - 4);
  };

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    updateArrows();
    el.addEventListener("scroll", updateArrows, { passive: true });
    return () => el.removeEventListener("scroll", updateArrows);
  }, [movies]);

  const scroll = (dir) => {
    const el = ref.current;
    if (!el) return;
    el.scrollBy({ left: dir * CARD_WIDTH * 3, behavior: "smooth" });
  };

  return (
    <div style={{ marginBottom: 36 }}>
      <h2
        style={{
          fontSize: 20,
          fontWeight: 700,
          margin: "0 0 10px",
          paddingLeft: 50,
          color: "#e5e5e5",
        }}
      >
        {label}
      </h2>
      <div style={{ position: "relative", overflowY: "visible" }}>
        {canLeft && (
          <button onClick={() => scroll(-1)} style={arrowBtn("left")}>
            <I.ChevL />
          </button>
        )}
        <div
          ref={ref}
          style={{
            display: "flex",
            gap: 8,
            overflowX: "auto",
            overflowY: "visible",
            paddingLeft: 50,
            paddingRight: 50,
            paddingTop: 20,
            paddingBottom: 20,
            scrollbarWidth: "none",
            msOverflowStyle: "none",
            WebkitOverflowScrolling: "touch",
          }}
        >
          {movies.map((m) => (
            <MovieCard
              key={m.id}
              movie={m}
              onSetHero={onSetHero}
              onPlay={onPlay}
              inList={myList ? myList.some((x) => x.id === m.id) : false}
              onToggleList={onToggleList}
            />
          ))}
        </div>
        {canRight && (
          <button onClick={() => scroll(1)} style={arrowBtn("right")}>
            <I.ChevR />
          </button>
        )}
      </div>
    </div>
  );
}

const arrowBtn = (side) => ({
  position: "absolute",
  [side]: 0,
  top: 0,
  bottom: 0,
  zIndex: 15,
  background: "rgba(20,20,20,0.85)",
  border: "none",
  color: "white",
  cursor: "pointer",
  width: 50,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  borderRadius: side === "left" ? "4px 0 0 4px" : "0 4px 4px 0",
  transition: "background 0.2s",
});

